    public class Permission
    {
        public string Name { get; set; } = string.Empty;
        public string Resource { get; set; } = string.Empty;
        public List<string> AllowedActions { get; set; } = new List<string>();

        public bool CanPerform(string action)
        {
            return AllowedActions.Contains(action, StringComparer.OrdinalIgnoreCase);
        }
    }

    public class PermissionSet
    {
        public List<Permission> Permissions { get; set; } = new List<Permission>();

        public bool HasPermission(string resource, string action)
        {
            foreach (var perm in Permissions)
            {
                if (string.Equals(perm.Resource, resource, StringComparison.OrdinalIgnoreCase)
                    && perm.CanPerform(action))
                {
                    return true;
                }
            }
            return false;
        }

        public void GrantPermission(string name, string resource, params string[] actions)
        {
            var existing = Permissions.Find(p =>
                string.Equals(p.Resource, resource, StringComparison.OrdinalIgnoreCase));

            if (existing != null)
            {
                foreach (var action in actions)
                {
                    if (!existing.AllowedActions.Contains(action, StringComparer.OrdinalIgnoreCase))
                    {
                        existing.AllowedActions.Add(action);
                    }
                }
            }
            else
            {
                Permissions.Add(new Permission
                {
                    Name = name,
                    Resource = resource,
                    AllowedActions = new List<string>(actions)
                });
            }
        }

        public void RevokePermission(string resource, string action)
        {
            var perm = Permissions.Find(p =>
                string.Equals(p.Resource, resource, StringComparison.OrdinalIgnoreCase));
            perm?.AllowedActions.RemoveAll(a =>
                string.Equals(a, action, StringComparison.OrdinalIgnoreCase));
        }
    }

