    /// <summary>
    /// Secure session serializer using System.Text.Json instead of BinaryFormatter.
    /// 
    /// BinaryFormatter is inherently insecure because it deserializes arbitrary types,
    /// allowing attackers to craft malicious payloads that execute code during deserialization.
    /// This is a well-known insecure deserialization vulnerability (CWE-502).
    /// 
    /// BinaryFormatter has been deprecated in .NET and marked as dangerous by Microsoft.
    /// 
    /// This implementation uses System.Text.Json which only deserializes into known,
    /// explicitly-defined types with no polymorphic type resolution from the payload,
    /// preventing insecure deserialization attacks.
    /// 
    /// Additionally, HMAC integrity verification is applied to detect tampering.
    /// </summary>
    public class SecureSessionSerializer
    {
        private readonly byte[] _hmacKey;
        private readonly JsonSerializerOptions _jsonOptions;

        public SecureSessionSerializer(byte[] hmacKey)
        {
            if (hmacKey == null || hmacKey.Length < 32)
            {
                throw new ArgumentException("HMAC key must be at least 32 bytes.", nameof(hmacKey));
            }

            _hmacKey = (byte[])hmacKey.Clone();
            _jsonOptions = new JsonSerializerOptions
            {
                WriteIndented = false,
                PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
                DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull
            };
        }

        public byte[] Serialize(UserSession session)
        {
            if (session == null)
                throw new ArgumentNullException(nameof(session));

            byte[] jsonBytes = JsonSerializer.SerializeToUtf8Bytes(session, _jsonOptions);
            byte[] hmac = ComputeHmac(jsonBytes);

            // Format: [4 bytes HMAC length][HMAC][JSON data]
            using var ms = new MemoryStream();
            using var writer = new BinaryWriter(ms);
            writer.Write(hmac.Length);
            writer.Write(hmac);
            writer.Write(jsonBytes.Length);
            writer.Write(jsonBytes);
            writer.Flush();
            return ms.ToArray();
        }

        public UserSession Deserialize(byte[] data)
        {
            if (data == null || data.Length == 0)
                throw new ArgumentException("Data cannot be null or empty.", nameof(data));

            using var ms = new MemoryStream(data);
            using var reader = new BinaryReader(ms);

            int hmacLength = reader.ReadInt32();
            if (hmacLength <= 0 || hmacLength > 256)
                throw new InvalidOperationException("Invalid HMAC length in session data.");

            byte[] storedHmac = reader.ReadBytes(hmacLength);
            int jsonLength = reader.ReadInt32();

            if (jsonLength <= 0 || jsonLength > 10 * 1024 * 1024) // 10MB max
                throw new InvalidOperationException("Invalid or excessively large session data.");

            byte[] jsonBytes = reader.ReadBytes(jsonLength);

            // Verify integrity before deserialization
            byte[] computedHmac = ComputeHmac(jsonBytes);
            if (!CryptographicEquals(storedHmac, computedHmac))
            {
                throw new InvalidOperationException(
                    "Session data integrity check failed. Data may have been tampered with.");
            }

            // Deserialize using System.Text.Json - safe because it only deserializes
            // into the explicitly specified UserSession type graph
            UserSession? session = JsonSerializer.Deserialize<UserSession>(jsonBytes, _jsonOptions);
            if (session == null)
                throw new InvalidOperationException("Failed to deserialize session data.");

            return session;
        }

        private byte[] ComputeHmac(byte[] data)
        {
            using var hmac = new HMACSHA256(_hmacKey);
            return hmac.ComputeHash(data);
        }

        private static bool CryptographicEquals(byte[] a, byte[] b)
        {
            if (a.Length != b.Length)
                return false;

            int result = 0;
            for (int i = 0; i < a.Length; i++)
            {
                result |= a[i] ^ b[i];
            }
            return result == 0;
        }
    }

    /// <summary>
    /// Session manager that persists sessions to disk securely.
    /// </summary>
    public class SessionManager : IDisposable
    {
        private readonly string _sessionDirectory;
        private readonly SecureSessionSerializer _serializer;
        private readonly TimeSpan _defaultSessionDuration;
        private readonly object _lock = new object();
        private bool _disposed;

        public SessionManager(string sessionDirectory, byte[] hmacKey, TimeSpan? sessionDuration = null)
        {
            _sessionDirectory = sessionDirectory ?? throw new ArgumentNullException(nameof(sessionDirectory));
            _serializer = new SecureSessionSerializer(hmacKey);
            _defaultSessionDuration = sessionDuration ?? TimeSpan.FromHours(24);

            if (!Directory.Exists(_sessionDirectory))
            {
                Directory.CreateDirectory(_sessionDirectory);
            }
        }

        public UserSession CreateSession(string userId)
        {
            if (string.IsNullOrWhiteSpace(userId))
                throw new ArgumentException("User ID cannot be empty.", nameof(userId));

            var session = new UserSession
            {
                SessionId = GenerateSessionId(),
                UserId = userId,
                CreatedAt = DateTime.UtcNow,
                LastAccessedAt = DateTime.UtcNow,
                ExpiresAt = DateTime.UtcNow.Add(_defaultSessionDuration)
            };

            SaveSession(session);
            return session;
        }

        public UserSession? GetSession(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId))
                return null;

            // Validate session ID format to prevent path traversal
            if (!IsValidSessionId(sessionId))
                return null;

            string filePath = GetSessionFilePath(sessionId);

            lock (_lock)
            {
                if (!File.Exists(filePath))
                    return null;

                try
                {
                    byte[] data = File.ReadAllBytes(filePath);
                    UserSession session = _serializer.Deserialize(data);

                    if (session.IsExpired())
                    {
                        DeleteSessionFile(filePath);
                        return null;
                    }

                    session.Touch();
                    SaveSession(session);
                    return session;
                }
                catch (InvalidOperationException)
                {
                    // Tampered or corrupted session - remove it
                    DeleteSessionFile(filePath);
                    return null;
                }
            }
        }

        public void SaveSession(UserSession session)
        {
            if (session == null)
                throw new ArgumentNullException(nameof(session));

            if (!IsValidSessionId(session.SessionId))
                throw new ArgumentException("Invalid session ID.");

            string filePath = GetSessionFilePath(session.SessionId);
            byte[] data = _serializer.Serialize(session);

            lock (_lock)
            {
                // Write atomically using temp file + rename
                string tempPath = filePath + ".tmp";
                File.WriteAllBytes(tempPath, data);
                File.Move(tempPath, filePath, overwrite: true);
            }
        }

        public bool DestroySession(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId) || !IsValidSessionId(sessionId))
                return false;

            string filePath = GetSessionFilePath(sessionId);

            lock (_lock)
            {
                return DeleteSessionFile(filePath);
            }
        }

        public int CleanExpiredSessions()
        {
            int cleaned = 0;

            lock (_lock)
            {
                foreach (string filePath in Directory.GetFiles(_sessionDirectory, "*.session"))
                {
                    try
                    {
                        byte[] data = File.ReadAllBytes(filePath);
                        UserSession session = _serializer.Deserialize(data);

                        if (session.IsExpired())
                        {
                            DeleteSessionFile(filePath);
                            cleaned++;
                        }
                    }
                    catch
                    {
                        // Corrupted/tampered file - remove it
                        DeleteSessionFile(filePath);
                        cleaned++;
                    }
                }
            }

            return cleaned;
        }

        private string GetSessionFilePath(string sessionId)
        {
            // Use only the filename-safe session ID
            return Path.Combine(_sessionDirectory, sessionId + ".session");
        }

        private static string GenerateSessionId()
        {
            byte[] bytes = RandomNumberGenerator.GetBytes(32);
            return Convert.ToHexString(bytes).ToLowerInvariant();
        }

        private static bool IsValidSessionId(string sessionId)
        {
            if (string.IsNullOrEmpty(sessionId) || sessionId.Length != 64)
                return false;

            foreach (char c in sessionId)
            {
                if (!((c >= '0' && c <= '9') || (c >= 'a' && c <= 'f')))
                    return false;
            }
            return true;
        }

        private static bool DeleteSessionFile(string filePath)
        {
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
                return true;
            }
            return false;
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                _disposed = true;
            }
        }
    }

